uint extMain::computePathDir(const Point& p1, const Point& p2, uint* length)
{
  int len;
  if (p2.getX() == p1.getX()) {
    len = p2.getY() - p1.getY();
  } else {
    len = p2.getX() - p1.getX();
  }

  if (len > 0) {
    *length = len;
    return 0;
  }
  *length = -len;
  return 1;
}

